static double b_cnfw_sav;

/*--------------------------------------------------------------
  approximated cored nfw
*/

double phi_acnfw_dl(double x, double y, double q, double b)
{
  int i, j;
  double f, p;

  calc_jp_acnfw(b, &j, &p);
  
  f = 0.0;
  for(i=0;i<N_CSE_CNFW;i++){
    f = f + (1.0 - p) * phi_cse_dl(x, y, par_cse_cnfw[j][2 * i], q) * par_cse_cnfw[j][2 * i + 1];
  }
  for(i=0;i<N_CSE_CNFW;i++){
    f = f + p * phi_cse_dl(x, y, par_cse_cnfw[j+1][2 * i], q) * par_cse_cnfw[j+1][2 * i + 1];
  }

  return f;
}

void ddphi_acnfw_dl(double x, double y, double q, double b, double *pxx, double *pxy, double *pyy)
{
  int i, j;
  double p, p1, p2, p3, pp1, pp2, pp3;

  calc_jp_acnfw(b, &j, &p);

  pp1 = 0.0;
  pp2 = 0.0;
  pp3 = 0.0;

  for(i=0;i<N_CSE_CNFW;i++){
    ddphi_cse_dl(x, y, par_cse_cnfw[j][2 * i], q, &p1, &p2, &p3);
    pp1 = pp1 + (1.0 - p) * par_cse_cnfw[j][2 * i + 1] * p1;
    pp2 = pp2 + (1.0 - p) * par_cse_cnfw[j][2 * i + 1] * p2;
    pp3 = pp3 + (1.0 - p) * par_cse_cnfw[j][2 * i + 1] * p3;
  }
  for(i=0;i<N_CSE_CNFW;i++){
    ddphi_cse_dl(x, y, par_cse_cnfw[j+1][2 * i], q, &p1, &p2, &p3);
    pp1 = pp1 + p * par_cse_cnfw[j+1][2 * i + 1] * p1;
    pp2 = pp2 + p * par_cse_cnfw[j+1][2 * i + 1] * p2;
    pp3 = pp3 + p * par_cse_cnfw[j+1][2 * i + 1] * p3;
  }

  *pxx = pp1;
  *pxy = pp2;
  *pyy = pp3;

  return;
}

void alpha_acnfw_dl(double x, double y, double q, double b, double *ax, double *ay)
{
  int i, j;
  double p, p1, p2, pp1, pp2;

  calc_jp_acnfw(b, &j, &p);

  pp1 = 0.0;
  pp2 = 0.0;

  for(i=0;i<N_CSE_CNFW;i++){
    alpha_cse_dl(x, y, par_cse_cnfw[j][2 * i], q, &p1, &p2);
    pp1 = pp1 + (1.0 - p) * par_cse_cnfw[j][2 * i + 1] * p1;
    pp2 = pp2 + (1.0 - p) * par_cse_cnfw[j][2 * i + 1] * p2;
  }
  for(i=0;i<N_CSE_CNFW;i++){
    alpha_cse_dl(x, y, par_cse_cnfw[j+1][2 * i], q, &p1, &p2);
    pp1 = pp1 + p * par_cse_cnfw[j+1][2 * i + 1] * p1;
    pp2 = pp2 + p * par_cse_cnfw[j+1][2 * i + 1] * p2;
  }

  *ax = pp1;
  *ay = pp2;

  return;
}

void calc_jp_acnfw(double b, int *j, double *p)
{
  int jj;
  double lb, pp;

  if(b<=pow(10.0,CNFW_LB_MIN)){
    jj = 0;
    pp = 0.0;
  } else {
    lb = log10(b);
    jj = (int)((lb - (CNFW_LB_MIN)) / CNFW_LB_DLB);
    if(jj >= (NUM_NB_CNFW - 1)){
      jj = NUM_NB_CNFW - 2;
      pp = 1.0;
    } else { 
      pp = (lb - (CNFW_LB_MIN + ((double)jj) * CNFW_LB_DLB)) / CNFW_LB_DLB;
    }
  }

  *j = jj;
  *p = pp;
  
  return;
}

