double bkappa_cnfw_dl(double x, double b)
{
  double ff;

  if ((b < (1.0 + 0.03)) && (b > (1.0 - 0.03))){
    if((x > (1.0 + 3.0e-6)) || (x < (1.0 - 3.0e-6))){
      return 0.5*((((3.0 * x * x - 2.0) * f_cnfw(x) + (log(4.0 / (x * x)) + x * x * (log(x * x / 4.0) - 1.0))) / (x * x * (1.0 - x * x))) * (-1.0)
	      + (((-1.0) * (1.0 + 2.0 * x * x) / (3.0 * (x * x - 1.0 ) * (x * x - 1.0))) + x * x * f_cnfw(x) / ((1.0 - x * x) * (1.0 - x * x))) * (b - 1.0));
    } else {
      return 0.5 * ((5.0 / 3.0) - log(4.0) + ((-44.0 / 15.0) + log(16.0)) * (x - 1.0) + (((-2.0) / 15.0) + (4.0 * (x - 1.0) / 35.0)) * (b - 1.0));
    }
  } else {
    if(b < 1.0e-30){
      ff = 0.0;
    } else {
      ff = f_cnfw(x / b);
    }

    if(b<1.0e-7){
      return bkappa_nfw_dl_cnfw(x);
    } else if((x > 1.0e-3) || (x > b)){
      return (0.5 / ((b - 1.0) * (b - 1.0) * x * x)) * ((1.0 - b) * (1.0 - b) * log(x * x / 4.0) - b * b * log(b * b) + 2.0 * (b * b - x * x) * ff + 2.0 * (1.0 + b * (x * x - 2.0)) * f_cnfw(x));
    } else {
      return 0.5 * (((b - 1.0 - log(b)) / ((b - 1.0) * (b - 1.0))) + x * x * (1.0 - b * b * b - 2.0 * log(2.0) + 2.0 * b * b * b * log(2.0) - 2.0 * log(b) + 2.0 * log(x) - 2.0 * b * b * b * log(x)) / (2.0 * (b - 1.0) * (b - 1.0) * b * b)); 
    }
  }
}

double bkappa_nfw_dl_cnfw(double x)
{
  if(x > (1.0 + 1.0e-9)){
    return (2.0 * atan(sqrt((x - 1.0) / (x + 1.0))) / (x * sqrt(x * x - 1.0)) + log(0.5 * x) / x) / x;
  } else if(x < (1.0 - 1.0e-9)){
    if(x > 8.0e-6){
      return (2.0 * atanh(sqrt((1.0 - x) / (x + 1.0))) / (x * sqrt(1.0 - x * x)) + log(0.5 * x) / x) / x;
    } else {
      return 0.5 * log(2.0 / x);
    } 
  } else {
    return 1.0 + log(0.5);
  }
}

double kappa_cnfw_dl(double x, double b)
{
  double ff;

  if ((b < (1.0 + 0.03)) && (b > (1.0 - 0.03))){
    if((x > (1.0 + 1.0e-6)) || (x < (1.0 - 1.0e-6))){
      return 0.5 * ((2.0 * x * x + 1.0 - 3.0 * x * x * f_cnfw(x)) / (2.0 * (x * x - 1.0) * (x * x - 1.0))
		    + (b - 1.0) * (((-13.0) * x * x - 2.0 + 3.0 * x * x * (4.0 + x * x) * f_cnfw(x)) / (6.0 * (1.0 - x * x) * (1.0 - x * x) * (1.0 - x * x))));
    } else {
      return 0.5 * (((1.0 / 5.0) - 6.0 * (x - 1.0) / 35.0) + (b - 1.0) * (((-8.0) / 105.0)+ 32.0 * (x - 1.0) / 315.0));
    }
  } else {
    if(b < 1.0e-30){
      ff = 0.0;
    } else {
      ff = f_cnfw(x / b);
    }
    
    if((x > (1.0 + 1.0e-6)) || (x < (1.0 - 1.0e-6))){
      return (0.5 / ((b - 1.0) * (b - 1.0))) * (((1.0 - b - (1.0 - b * x * x) * f_cnfw(x)) / (x * x - 1.0)) - ff);
    } else {
      return (0.5 / ((b - 1.0) * (b - 1.0))) * (((1.0 / 3.0) * (1.0 + 2.0 * b) - (2.0 * (x - 1.0) * (3.0 + 2.0 * b) / 15.0)) - ff);
    }
  }
}

double f_cnfw(double x)
{
  if(x < 3.0e-4){
    return log(2.0 / x) + 0.25 * ((-1.0) + 2.0 * log (2.0 / x)) * x * x;
  } else if(x > (1.0 + 1.0e-6)){
    return atan(sqrt(x * x - 1.0)) / sqrt(x * x - 1.0);
  } else if(x < (1.0 - 1.0e-6)){
    return atanh(sqrt(1.0 - x * x)) / sqrt(1.0 - x * x);
  } else {
    return 1.0 - (2.0 * (x - 1.0) / 3.0);
  }
}

